using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Running;
using TextAnalysis;

BenchmarkRunner.Run<TextAnalyzerBenchmarks>();

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    // A realistic-ish paragraph to benchmark against
    private const string SampleText =
        "The quick brown fox jumps over the lazy dog and then the fox ran across the field to find " +
        "another lazy dog sleeping under a tall oak tree while birds were singing beautiful songs in " +
        "the bright morning sunshine that illuminated the entire countryside with golden rays of warm " +
        "light spreading across the meadows and hills where wildflowers bloomed in every color imaginable " +
        "creating a breathtaking panorama of natural beauty that captivated every observer who happened " +
        "to pass by on that wonderful magnificent extraordinary day full of surprises and adventures";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

